svg.script:
    
    // Configurazioni di base
    const width = 1200;         // Larghezza dell'SVG
    const height = 500;        // Altezza dell'SVG
    const columns = 120;        // Numero di colonne in cui generare i caratteri
    const spawnInterval = 5; // Intervallo (ms) tra la generazione di nuovi caratteri
    const minSpeed = 1;        // Velocità minima di discesa (pixel/frame)
    const maxSpeed = 3;        // Velocità massima di discesa (pixel/frame)

    // Caratteri possibili (puoi aggiungere/rimuovere a piacere)
    const chars = "01A01B01C01D01E01F01G01H01I01J01K01L01M01N01O01P01Q01R01S01T01U01V01W01X01Y01Z01a01b01c01d01e01f01g01h01i01j01k01l01m01n01o01p01q01r01s01t01u01v01w01x01y01z01";

    // Selettore del root SVG
    const svgRoot = document.documentElement;

    // Funzione per creare un singolo carattere "in caduta" in una certa colonna
    function createFallingChar(x) {
      // Crea un elemento <text> SVG
      const textEl = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textEl.setAttribute("x", x);
      textEl.setAttribute("y", "-20"); // parte appena sopra lo schermo
      textEl.setAttribute("fill", "limegreen");
      textEl.setAttribute("font-family", "monospace");
      textEl.setAttribute("font-size", "16");

      // Scegli un carattere casuale dalla stringa chars
      const randomChar = chars[Math.floor(Math.random() * chars.length)];
      textEl.textContent = randomChar;

      // Aggiunge l'elemento al DOM SVG
      svgRoot.appendChild(textEl);

      // Imposta una velocità casuale
      const speed = Math.random() * (maxSpeed - minSpeed) + minSpeed;

      // Funzione per animare la caduta
      function fall() {
        const currentY = parseFloat(textEl.getAttribute("y"));
        if (currentY > height + 50) {
          // Se esce dallo schermo, rimuovilo
          svgRoot.removeChild(textEl);
          return;
        }
        // Aggiorna la posizione Y
        textEl.setAttribute("y", currentY + speed);
        // Richiede il prossimo frame di animazione
        requestAnimationFrame(fall);
      }

      // Avvia l’animazione
      requestAnimationFrame(fall);
    }

    // Calcola la distanza orizzontale tra le colonne
    const columnSpacing = width / columns;

    // Genera un carattere in una colonna casuale a intervalli regolari
    setInterval(() => {
      const randomColumn = Math.floor(Math.random() * columns);
      const xPos = randomColumn * columnSpacing;
      createFallingChar(xPos);
    }, spawnInterval);
